{"code": "import json
import re

# Load business data
businesses = locals()['var_functions.query_db:17']

# Filter businesses that accept credit cards and extract categories
credit_card_businesses = []
categories_business_map = {}

# Process all businesses that accept credit cards
for business in businesses:
    if business.get('attributes') != 'None' and business.get('attributes'):
        if isinstance(business.get('attributes'), dict):
            if business['attributes'].get('BusinessAcceptsCreditCards') == 'True':
                credit_card_businesses.append(business)

# Process descriptions to extract categories
for business in credit_card_businesses:
    desc = business.get('description', '')
    categories = []

    # Pattern 1: "services in [categories]"
    if 'services in ' in desc:
        parts = desc.split('services in ')
        if len(parts) > 1:
            cat_text = parts[1]
            # Split by comma and "and"
            raw_cats = [c.strip() for c in cat_text.split(',')]
            for cat in raw_cats:
                if ' and ' in cat:
                    subcats = [c.strip() for c in cat.split(' and ')]
                    categories.extend(subcats)
                else:
                    categories.append(cat)

    # Pattern 2: "including [categories]"
    elif 'including ' in desc:
        parts = desc.split('including ')
        if len(parts) > 1:
            cat_text = parts[1]
            raw_cats = [c.strip() for c in cat_text.split(',')]
            for cat in raw_cats:
                if ' and ' in cat:
                    subcats = [c.strip() for c in cat.split(' and ')]
                    categories.extend(subcats)
                else:
                    categories.append(cat)

    # Pattern 3: "services and products in the fields of [categories]"  
    elif 'services and products in the fields of ' in desc:
        parts = desc.split('services and products in the fields of ')
        if len(parts) > 1:
            cat_text = parts[1]
            raw_cats = [c.strip() for c in cat_text.split(',')]
            for cat in raw_cats:
                if ' and ' in cat:
                    subcats = [c.strip() for c in cat.split(' and ')]
                    categories.extend(subcats)
                else:
                    categories.append(cat)

    # Clean up categories
    cleaned_categories = []
    for cat in categories:
        # Remove period at end
        cat = cat.rstrip('.')
        cleaned_categories.append(cat)

    # Assign cleaned categories to business
    for cat in cleaned_categories:
        if cat:
            if cat not in categories_business_map:
                categories_business_map[cat] = []
            categories_business_map[cat].append(business['business_id'])

# Count businesses per category
category_counts = {}
for cat, businesses_list in categories_business_map.items():
    if cat and cat != '':
        category_counts[cat] = len(businesses_list)

# Sort by count descending
sorted_categories = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)

print("Number of credit card businesses: " + str(len(credit_card_businesses)))
print("Number of distinct categories found: " + str(len(sorted_categories)))
print("Top categories by business count:")
for i, (cat, count) in enumerate(sorted_categories[:10]):
    print(str(i+1) + ". " + cat + ": " + str(count))

# Save results for next steps
result_data = {
    "credit_card_businesses": credit_card_businesses,
    "categories_business_map": categories_business_map,
    "category_counts": category_counts,
    "sorted_categories": sorted_categories
}

with open('/tmp/category_analysis.json', 'w') as f:
    json.dump(result_data, f)

print('__RESULT__:')
print(json.dumps('Category analysis complete, saved to file'))"} <|tool_call_end|> <|tool_calls_section_end|>

